mapper.select:
SELECT m.ID, m.EQUIP_ID, m.FAULT_FIND_TIME, m.EMERGENCY_LEVEL, m.MAINT_TYPE_CODE, m.MAINT_TYPE_NAME, m.IS_STOPPED, m.FAULT_DESC, m.REPORT_TYPE_CODE, m.REPORT_TYPE_NAME, m.DISPATCH_TYPE_CODE, m.DISPATCH_TYPE_NAME, m.MAINT_ORG_ID, m.MAINT_ORG_NAME, m.MAINT_LEADER_ID, m.MAINT_LEADER_NAME, m.MAINT_LEADER_MOBILE, m.IS_SPECIAL_JOB, m.SPECIAL_JOB_CODE, m.SPECIAL_JOB_NAME, m.DISPATCHER_ID, m.DISPATCHER_NAME, m.DISPATCH_TIME, m.MAINT_START_TIME, m.MAINT_END_TIME, m.MAINT_REMARK, m.ACCEPTER_ID, m.ACCEPTER_NAME, m.ACCEPTANCE_TIME, m.ACCEPTANCE_REMARK, m.STATUS, m.WORK_ORDER_NO, m.CANCEL_BY, m.CANCEL_BY_NAME, m.CANCEL_TIME, m.CANCEL_REMARK, m.MANT_APP_NUMBER, m.CREATE_BY, m.CREATE_BY_NAME, m.CREATE_TIME, m.UPDATE_BY, m.UPDATE_BY_NAME, m.UPDATE_TIME, m.DEL_FLAG, e.EQUIP_NAME, e.EQUIP_CODE, e.EQUIP_SMALL_CATEGORY_NAME, u.DEPT_NAME as useOrgName, -- 维修时长（小时）：维修结束时间 - 维修开始时间 CASE WHEN m.MAINT_START_TIME IS NOT NULL AND m.MAINT_END_TIME IS NOT NULL THEN ROUND((m.MAINT_END_TIME - m.MAINT_START_TIME) * 24, 2) ELSE NULL END AS MAINT_DURATION, -- 故障时长（小时）：优先取维修结束时间，否则取当前时间 CASE WHEN m.FAULT_FIND_TIME IS NOT NULL AND m.MAINT_END_TIME IS NOT NULL THEN ROUND((m.MAINT_END_TIME - m.FAULT_FIND_TIME) * 24, 2) WHEN m.FAULT_FIND_TIME IS NOT NULL THEN ROUND((SYSDATE - m.FAULT_FIND_TIME) * 24, 2) ELSE NULL END AS FAULT_DURATION FROM E_MAINT_INFO m LEFT JOIN E_M_EQPT_INFO e ON m.EQUIP_ID = e.ID AND e.DEL_FLAG = 0 LEFT JOIN SYS_DEPT u ON e.USE_ORG_ID = u.ID
m.DEL_FLAG = 0
AND m.EQUIP_ID = #{equipId}
AND e.EQUIP_NAME LIKE #{equipNamePattern}
AND e.EQUIP_CODE LIKE #{equipCodePattern}
AND m.WORK_ORDER_NO LIKE #{workOrderNoPattern}
AND m.MAINT_TYPE_CODE = #{maintTypeCode}
AND m.DISPATCH_TYPE_CODE = #{dispatchTypeCode}
AND m.EMERGENCY_LEVEL = #{emergencyLevel}
AND m.IS_STOPPED = #{isStopped}
AND m.STATUS = #{status}
AND (m.CREATE_BY = #{createBy} OR m.MAINT_LEADER_ID = #{maintLeaderId})
ORDER BY m.CREATE_TIME DESC

SELECT m.ID, m.STATUS, m.WORK_ORDER_NO FROM E_MAINT_INFO m WHERE m.DEL_FLAG = 0
AND m.ID IN
#{id}

mapper.update:
UPDATE E_MAINT_INFO SET STATUS = #{status,jdbcType=NUMERIC}, CANCEL_BY = #{loginUserId,jdbcType=NUMERIC}, CANCEL_BY_NAME = #{loginUserName,jdbcType=VARCHAR}, CANCEL_TIME = #{now,jdbcType=TIMESTAMP}, CANCEL_REMARK = #{cancelRemark,jdbcType=VARCHAR} WHERE DEL_FLAG = 0
AND ID IN
#{id}

UPDATE E_MAINT_INFO SET DEL_FLAG = 1, DELETE_BY = #{loginUserId,jdbcType=NUMERIC}, DELETE_BY_NAME = #{loginUserName,jdbcType=VARCHAR}, DELETE_TIME = #{now,jdbcType=TIMESTAMP} WHERE DEL_FLAG = 0
AND ID IN
#{id}

mapper.select:
SELECT
a.APP_NUMBER,
a.APP_NUMBER || '-' || a.MAINTENANCE_UNIT_NAME AS APP_UNIT_NAME
FROM E_IC_MAINT_PROJ_APPLY a
WHERE a.EQUIP_ID = #{equipId}
AND a.APP_TYPE = #{appType}


    AND a.APP_NUMBER LIKE #{appNumberPattern}

AND NOT EXISTS (
SELECT 1
FROM E_MAINT_INFO b
WHERE b.MANT_APP_NUMBER = a.APP_NUMBER
AND b.DEL_FLAG = 0
AND b.STATUS != 7

    AND b.ID != #{maintInfoId}

)
